def bubble_trace(arr):
    arr = arr[:]
    traces = []

    n = len(arr)
    for i in range(n - 1):
        for j in range(0, n - 1 - i):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
        traces.append(arr[:])

    return traces

print(bubble_trace([5, 1, 4, 2]))

def selection_trace(arr):
    arr = arr[:]
    traces = []

    n = len(arr)
    for i in range(n - 1):
        min_index = i
        for j in range(i + 1, n):
            if arr[j] < arr[min_index]:
                min_index = j
        arr[i], arr[min_index] = arr[min_index], arr[i]
        traces.append(arr[:])

    return traces

print(selection_trace([64, 25, 12, 22, 11]))

def compare_sorting_algorithms():
    return {
        "bubble_sort": "Uses many adjacent swaps; large elements move to the end.",
        "selection_sort": "Selects the minimum from the unsorted part and places it at the front.",
        "insertion_sort": "Builds a sorted left section and works well for nearly sorted arrays."
    }

print(compare_sorting_algorithms())
